#include <stdio.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        long long X, Y;
        scanf("%lld %lld", &X, &Y);
        long long a1 = 500 - 2 * X;
        if (a1 < 0) a1 = 0;
        long long b1 = 1000 - 4 * (X + Y);
        if (b1 < 0) b1 = 0;
        long long total1 = a1 + b1;
        long long b2 = 1000 - 4 * Y;
        if (b2 < 0) b2 = 0;
        long long a2 = 500 - 2 * (X + Y);
        if (a2 < 0) a2 = 0;
        long long total2 = b2 + a2;
        long long ans = total1 > total2 ? total1 : total2;
        printf("%lld\n", ans);
    }
    return 0;
}

